class BackgroundTaskService : Service() {

    companion object {
        private const val TAG = "BackgroundTaskService"
        private const val NOTIFICATION_CHANNEL_ID = "background_task_channel"
        private const val NOTIFICATION_ID = 1001
        
        const val ACTION_SYNC_DATA = "com.example.systemoptimization.ACTION_SYNC_DATA"
        const val ACTION_CLEANUP = "com.example.systemoptimization.ACTION_CLEANUP"
        
        const val EXTRA_TASK_TYPE = "task_type"
        const val EXTRA_SYNC_SOURCE = "sync_source"
        const val EXTRA_CLEANUP_TYPE = "cleanup_type"
        const val EXTRA_PRIORITY = "priority"
        const val EXTRA_CALLER_PACKAGE = "caller_package"
        const val EXTRA_AUTH_TOKEN = "auth_token"
        
        const val TASK_TYPE_SYNC = "sync"
        const val TASK_TYPE_CLEANUP = "cleanup"
        
        const val CLEANUP_TYPE_CACHE = "cache"
        const val CLEANUP_TYPE_TEMP = "temp"
        const val CLEANUP_TYPE_LOGS = "logs"
        const val CLEANUP_TYPE_ALL = "all"
        
        private const val MAX_CONCURRENT_TASKS = 3
        private const val TASK_TIMEOUT_MS = 300000L
    }

    private lateinit var handlerThread: HandlerThread
    private lateinit var serviceHandler: Handler
    private val activeTasks = ConcurrentHashMap<Int, TaskInfo>()
    private val taskIdCounter = AtomicInteger(0)
    private val whitelistedPackages = setOf(
        "com.example.systemoptimization",
        "com.example.systemoptimization.admin"
    )

    data class TaskInfo(
        val taskId: Int,
        val taskType: String,
        val startTime: Long,
        val callerPackage: String
    )

    override fun onCreate() {
        super.onCreate()
        Log.d(TAG, "Service created")
        
        handlerThread = HandlerThread("BackgroundTaskThread", Process.THREAD_PRIORITY_BACKGROUND)
        handlerThread.start()
        serviceHandler = Handler(handlerThread.looper)
        
        createNotificationChannel()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (intent == null) {
            Log.w(TAG, "Received null intent")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val callerPackage = intent.getStringExtra(EXTRA_CALLER_PACKAGE) ?: ""
        
        if (!validateCaller(callerPackage, intent)) {
            Log.w(TAG, "Unauthorized caller: $callerPackage")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        if (activeTasks.size >= MAX_CONCURRENT_TASKS) {
            Log.w(TAG, "Maximum concurrent tasks reached")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val action = intent.action
        if (action == null) {
            Log.w(TAG, "No action specified")
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val taskId = taskIdCounter.incrementAndGet()
        
        serviceHandler.post {
            processTask(intent, action, taskId, startId, callerPackage)
        }

        return START_REDELIVER_INTENT
    }

    private fun validateCaller(callerPackage: String, intent: Intent): Boolean {
        if (callerPackage.isEmpty()) {
            return false
        }

        if (!whitelistedPackages.contains(callerPackage)) {
            return false
        }

        val authToken = intent.getStringExtra(EXTRA_AUTH_TOKEN) ?: ""
        return validateAuthToken(callerPackage, authToken)
    }

    private fun validateAuthToken(callerPackage: String, authToken: String): Boolean {
        if (authToken.isEmpty()) {
            return false
        }

        val expectedToken = generateAuthToken(callerPackage)
        return MessageDigest.isEqual(authToken.toByteArray(), expectedToken.toByteArray())
    }

    private fun generateAuthToken(callerPackage: String): String {
        val secret = "your_secret_key_here"
        val data = "$callerPackage:$secret"
        val digest = MessageDigest.getInstance("SHA-256")
        val hash = digest.digest(data.toByteArray())
        return hash.joinToString("") { "%02x".format(it) }
    }

    private fun processTask(intent: Intent, action: String, taskId: Int, startId: Int, callerPackage: String) {
        val taskType = when (action) {
            ACTION_SYNC_DATA -> TASK_TYPE_SYNC
            ACTION_CLEANUP -> TASK_TYPE_CLEANUP
            else -> {
                Log.w(TAG, "Unknown action: $action")
                stopSelf(startId)
                return
            }
        }

        val taskInfo = TaskInfo(taskId, taskType, System.currentTimeMillis(), callerPackage)
        activeTasks[taskId] = taskInfo

        showNotification("Processing $taskType task")

        try {
            when (action) {
                ACTION_SYNC_DATA -> handleDataSync(intent, taskId)
                ACTION_CLEANUP -> handleCleanup(intent, taskId)
            }
            
            Log.d(TAG, "Task $taskId completed successfully")
        } catch (e: Exception) {
            Log.e(TAG, "Error processing task $taskId", e)
        } finally {
            activeTasks.remove(taskId)
            
            if (activeTasks.isEmpty()) {
                stopForeground(true)
                stopSelf(startId)
            }
        }
    }

    private fun handleDataSync(intent: Intent, taskId: Int) {
        val syncSource = sanitizeInput(intent.getStringExtra(EXTRA_SYNC_SOURCE) ?: "default")
        val priority = intent.getIntExtra(EXTRA_PRIORITY, 0).coerceIn(0, 10)
        
        Log.d(TAG, "Starting data sync from source: $syncSource with priority: $priority")
        
        val syncManager = DataSyncManager(applicationContext)
        syncManager.performSync(syncSource, priority)
        
        Thread.sleep(2000)
        
        Log.d(TAG, "Data sync completed for task $taskId")
    }

    private fun handleCleanup(intent: Intent, taskId: Int) {
        val cleanupType = sanitizeInput(intent.getStringExtra(EXTRA_CLEANUP_TYPE) ?: CLEANUP_TYPE_CACHE)
        
        if (!isValidCleanupType(cleanupType)) {
            Log.w(TAG, "Invalid cleanup type: $cleanupType")
            return
        }
        
        Log.d(TAG, "Starting cleanup: $cleanupType")
        
        val cleanupManager = CleanupManager(applicationContext)
        
        when (cleanupType) {
            CLEANUP_TYPE_CACHE -> cleanupManager.cleanCache()
            CLEANUP_TYPE_TEMP -> cleanupManager.cleanTempFiles()
            CLEANUP_TYPE_LOGS -> cleanupManager.cleanLogs()
            CLEANUP_TYPE_ALL -> {
                cleanupManager.cleanCache()
                cleanupManager.cleanTempFiles()
                cleanupManager.cleanLogs()
            }
        }
        
        Thread.sleep(1500)
        
        Log.d(TAG, "Cleanup completed for task $taskId")
    }

    private fun sanitizeInput(input: String): String {
        return input.replace(Regex("[^a-zA-Z0-9_-]"), "").take(50)
    }

    private fun isValidCleanupType(type: String): Boolean {
        return type in setOf(CLEANUP_TYPE_CACHE, CLEANUP_TYPE_TEMP, CLEANUP_TYPE_LOGS, CLEANUP_TYPE_ALL)
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Background Tasks",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background task processing notifications"
            }
            
            val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun showNotification(message: String) {
        val notification = NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimization")
            .setContentText(message)
            .setSmallIcon(android.R.drawable.ic_menu_manage)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .build()

        startForeground(NOTIFICATION_ID, notification)
    }

    override fun onBind(intent: Intent?): IBinder? {
        return null
    }

    override fun onDestroy() {
        super.onDestroy()
        Log.d(TAG, "Service destroyed")
        handlerThread.quitSafely()
    }
}

class DataSyncManager(private val context: Context) {
    
    fun performSync(source: String, priority: Int) {
        Log.d("DataSyncManager", "Syncing data from $source with priority $priority")
        
        val sharedPrefs = context.getSharedPreferences("sync_data", Context.MODE_PRIVATE)
        sharedPrefs.edit().apply {
            putLong("last_sync_time", System.currentTimeMillis())
            putString("last_sync_source", source)
            putInt("last_sync_priority", priority)
            apply()
        }
        
        Thread.sleep(1000)
    }
}

class CleanupManager(private val context: Context) {
    
    fun cleanCache() {
        Log.d("CleanupManager", "Cleaning cache")
        try {
            context.cacheDir?.deleteRecursively()
            context.cacheDir?.mkdirs()
        } catch (e: Exception) {
            Log.e("CleanupManager", "Error cleaning cache", e)
        }
    }
    
    fun cleanTempFiles() {
        Log.d("CleanupManager", "Cleaning temp files")
        try {
            val tempDir = context.getDir("temp", Context.MODE_PRIVATE)
            tempDir.listFiles()?.forEach { file ->
                if (System.currentTimeMillis() - file.lastModified() > 86400000) {
                    file.delete()
                }
            }
        } catch (e: Exception) {
            Log.e("CleanupManager", "Error cleaning temp files", e)
        }
    }
    
    fun cleanLogs() {
        Log.d("CleanupManager", "Cleaning logs")
        try {
            val logsDir = context.getDir("logs", Context.MODE_PRIVATE)
            logsDir.listFiles()?.forEach { file ->
                if (System.currentTimeMillis() - file.lastModified() > 604800000) {
                    file.delete()
                }
            }
        } catch (e: Exception) {
            Log.e("CleanupManager", "Error cleaning logs", e)
        }
    }
}